<span class="line">  io<span class="token punctuation">.</span><span class="token function">emit</span><span class="token punctuation">(</span><span class="token string">&#39;gameState&#39;</span><span class="token punctuation">,</span> gameState<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
